// Webhook body carries { application_id } -- same subject as f05-trust-rollup (design.md
// SS8: 05 always operates at application scope, never bare card/claim scope, so the
// SS8.1 scoping rule is applied identically by every f05 workflow).
const item = $input.first().json;
const body = item.body || {};
const application_id = body.application_id || item.application_id;
if (!application_id) throw new Error('f05-verify-claims: application_id is required');
return [{ json: { application_id } }];

// Called by 06/09/10 (or a manual test) as a sub-workflow with { application_id }.
const item = $input.first().json || {};
const application_id = item.application_id;
if (!application_id) throw new Error('f05-verify-claims: application_id is required');
return [{ json: { application_id } }];

// One UUID per verification run -- echoed into every event payload below (design.md SS9's
// audit trail). require('crypto') -- globalThis.crypto is undefined inside this n8n
// build's actual Code-node VM sandbox (verified live 2026-07-19, restated in
// n8n/workflows/README-f05.md), even though a bare `docker exec node -e` process on the
// same container exposes it fine. Allow-listed via
// infra/n8n/docker-compose.yml's NODE_FUNCTION_ALLOW_BUILTIN=crypto,url -- same proven
// pattern as f03's and f05-trust-rollup's own Generate run_id nodes.
const { randomUUID } = require('crypto');
const inp = $input.first().json;
return [{ json: { application_id: inp.application_id, run_id: randomUUID() } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
const rows = await pgGet.call(this,
  'applications?id=eq.' + inp.application_id + '&select=id,company_id');
if (!rows || !rows.length) {
  throw new Error('f05-verify-claims: no application found for id ' + inp.application_id);
}
return [{ json: { ...inp, company_id: rows[0].company_id } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
// design.md SS8.1 route 3's founderIds -- resolved by the caller with a single-table
// lookup, matching f05-trust-rollup's identical node exactly (no shared import between
// generators; independent copy, same convention every f05 workflow follows).
const rows = await pgGet.call(this,
  'founder_company?company_id=eq.' + inp.company_id + '&select=founder_id');
const founder_ids = (rows || []).map(function (r) { return r.founder_id; }).filter(Boolean);
return [{ json: { ...inp, founder_ids } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
const rows = await pgGet.call(this,
  'score_formulas?axis=eq.trust&active=eq.true&select=version,config&limit=1');
if (!rows || !rows.length) {
  throw new Error("f05-verify-claims: no active score_formulas row for axis='trust'");
}
// design.md SS4.1 -- the router prefix_map + default_class live in config.router; read
// the live row here rather than a second hardcoded copy (this workflow's own instance of
// the LEFT-JOIN + literal-fallback discipline SS7.5 states for the view). lib/f05/router.js
// itself carries NO built-in prefix map for exactly this reason.
const router_config = (rows[0].config && rows[0].config.router) || { prefix_map: [], default_class: 'unverifiable' };
return [{ json: { ...inp, router_config } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
// design.md SS8.1's three OR'd routes, IDENTICAL query to f05-trust-rollup's own node of
// the same name (independent copy, no shared import between generators) -- the
// UNRESTRICTED superset; the company_id restriction on route 3 is applied downstream by
// trust.js's own scopeClaimsToApplication(), inlined into the ROUTE node below.
const orParts = [
  'application_id.eq.' + inp.application_id,
  'company_id.eq.' + inp.company_id,
];
if (inp.founder_ids && inp.founder_ids.length) {
  orParts.push('founder_id.in.(' + inp.founder_ids.join(',') + ')');
}
const cards = await pgGet.call(this,
  'cards?select=id,application_id,company_id,founder_id&or=(' + orParts.join(',') + ')');
return [{ json: { ...inp, scope_cards: cards || [] } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
const cardIds = (inp.scope_cards || []).map(function (c) { return c.id; });
let claimRows = [];
if (cardIds.length) {
  claimRows = await pgGet.call(this,
    'claim_trust?select=claim_id,card_id,topic,text_verbatim,source_kind,verification_status,' +
    'router_class,derived_status,n_supports,n_contradicts&card_id=in.(' + cardIds.join(',') + ')');
}
// Column-contract reconciliation (same term, same fix as B3's own tracker.md entry):
// claim_trust exposes only card_id, not the three card FKs the SS8.1 scope predicate
// needs -- merged in here from the cards rows the previous node already fetched. Also
// carries text_verbatim/source_kind, which f05-trust-rollup's OWN version of this node
// does not need (rollup math never reads a claim's text) but every SS5.1 check below does.
const cardsById = new Map((inp.scope_cards || []).map(function (c) { return [c.id, c]; }));
const rows = (claimRows || []).map(function (r) {
  const card = cardsById.get(r.card_id) || {};
  return {
    claim_id: r.claim_id, card_id: r.card_id, topic: r.topic, text_verbatim: r.text_verbatim,
    source_kind: r.source_kind, verification_status: r.verification_status,
    class: r.router_class, derived_status: r.derived_status,
    n_supports: r.n_supports, n_contradicts: r.n_contradicts,
    card_application_id: card.application_id || null,
    card_company_id: card.company_id || null,
    card_founder_id: card.founder_id || null,
  };
});
return [{ json: { ...inp, rows } }];

