// lib/f05/verifiers.js
// SOURCE OF TRUTH: lib/f05/verifiers.js
//
// Deterministic, zero-LLM verification checks for feature 05 (Truth-Gap
// Check & Trust Score), design.md SS5.1(b), SS5.1(c) and SS10.1. Plus the
// shared evidence-write helper both checks (and lib/f05/entity_gate.js's
// step-4 downgrade, via lib/f05/run.js -- task B3 -- which wires the two
// together) rely on to finalise an `evidence` row before it is inserted.
//
// Self-contained CommonJS. ZERO imports -- this file's body is pasted
// verbatim into an n8n Code node; n8n's sandbox cannot require() from the
// repo. No Date.now(), no Math.random(), no top-level side effects. SHA-256
// therefore uses the Web Crypto global (`globalThis.crypto.subtle`),
// available unflagged in Node 22 and in n8n's Code-node sandbox, never
// `require('crypto')` -- every hashing function here is ASYNC; callers must
// `await` it (same divergence lib/f02/normalize.js documents against
// lib/f04/provenance.js and lib/f07/hashes.js, which predate this
// constraint being confirmed live in an n8n Code node).
//
// docs/backlog/05-truth-gap-trust/plan.md, task B2.

'use strict';

// ============================================================================
// Shared hash helpers -- SS10.1's content_hash recipe.
//
// design.md writes the recipe as `sha256(a || b || c || ...)`, concatenation
// with no delimiter specified. A delimiter IS required (or "ab"+"c" and
// "a"+"bc" collide). This file uses the NUL byte, matching
// lib/f04/provenance.js's and lib/f07/hashes.js's own reasoning for the
// identical situation ("design.md leaves the join character unspecified" --
// SS10.1 here likewise never pins one): NUL is vanishingly unlikely to
// appear in any of the recipe's fields (uuids, enum-like `relation`/
// `check_id` strings, URLs, and free-text quotes/candidate keys, which --
// like lib/f04/provenance.js's own `query` field -- are the reason a literal
// space is not used as the delimiter here).
// ============================================================================

const HASH_FIELD_DELIMITER = '�';

async function sha256Hex(text) {
  const bytes = new TextEncoder().encode(text);
  const digest = await globalThis.crypto.subtle.digest('SHA-256', bytes);
  return Array.from(new Uint8Array(digest))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

function joinFields(parts) {
  return parts.map((part) => (part === null || part === undefined ? '' : String(part))).join(HASH_FIELD_DELIMITER);
}

// evidenceContentHash -- SS10.1's recipe, EXACTLY in this field order:
//   sha256(claim_id || relation || coalesce(source_url,'') ||
//          coalesce(quote,'') || check_id || candidate_key)
//
// `check_id` and `candidate_key` are the two discriminators SS10.1 adds
// beyond the schema comment's naive 4-field recipe (claim_id + relation +
// source_url + quote) -- the same pattern feature 04's provenance.js already
// established (its own `query` discriminator, added for the identical
// reason: several rows legitimately share NULL source_url/quote and would
// otherwise collide on evidence.content_hash's NOT NULL UNIQUE constraint).
//
// ⚠️ `run_id` must NEVER appear in this recipe (SS10.1, explicit warning):
// it is unique per execution, so an at-least-once redelivery would produce a
// NEW hash and a duplicate row -- and a duplicate `contradicts` row doubles
// contradiction_penalty from 0.30 to 0.60, halving a claim's trust because a
// webhook fired twice. Nothing below accepts or reads a run_id.
async function evidenceContentHash({ claimId, relation, sourceUrl, quote, checkId, candidateKey }) {
  return sha256Hex(joinFields([claimId, relation, sourceUrl, quote, checkId, candidateKey]));
}

// ============================================================================
// buildEvidenceRow -- the evidence-write helper. Takes the logical fields of
// one `evidence` row and returns it ready for INSERT, snake_case matching
// the table's own column names (db/schema.sql Task 6) so a caller can spread
// the result directly into an insert statement.
//
// Fails LOUD (throws), not silently, on the two invariants that must never
// slip through as a caller bug rather than a legitimate absence:
//   - raw_signal_id is REQUIRED on every row 05 writes (design.md SS2.1):
//     feature 03's negative-capability guard resolves a claim's source
//     through evidence.raw_signal_id, falling back to claims.source_kind's
//     wildcard when it is NULL -- a NULL here silently licenses a `not_met`
//     verdict on a criterion the evidence says nothing about.
//   - relation/tier must be one of evidence's own CHECK-constrained enum
//     values (db/schema.sql), so a typo'd caller fails at construction time,
//     not as an opaque Postgres 23514 several steps later.
//
// strength/quoteVerbatim/sourceUrl are nullable at the column level and stay
// nullable here; captured_at/id/created_at are DB-assigned defaults and are
// deliberately never set by this function (the "no Date.now()" rule extends
// to not fabricating a timestamp the database already generates correctly).
// ============================================================================

const VALID_RELATIONS = ['supports', 'contradicts', 'context'];
const VALID_TIERS = ['documented', 'discovered', 'inferred', 'missing'];

async function buildEvidenceRow(params) {
  const p = params || {};
  if (!p.claimId) throw new Error('buildEvidenceRow: claimId is required');
  if (VALID_RELATIONS.indexOf(p.relation) === -1) {
    throw new Error('buildEvidenceRow: relation must be one of ' + VALID_RELATIONS.join('/') + ', got: ' + p.relation);
  }
  if (VALID_TIERS.indexOf(p.tier) === -1) {
    throw new Error('buildEvidenceRow: tier must be one of ' + VALID_TIERS.join('/') + ', got: ' + p.tier);
  }
  if (!p.rawSignalId) {
    // Fail-closed by design (SS2.1) -- see file header. A caller that hits
    // this has a bug upstream (an unresolved or unpersisted raw_signal),
    // not a legitimate "no source" state: SS10.2 requires Tavily results to
    // be written to raw_signals FIRST, before any evidence row cites them.
    throw new Error('buildEvidenceRow: rawSignalId is required on every evidence row this feature writes (design.md SS2.1)');
  }
  if (!p.checkId) throw new Error('buildEvidenceRow: checkId is required (SS10.1 content_hash discriminator)');

  // candidateKey defaults to checkId itself for single-candidate-per-claim
  // checks (SS10.1: "candidate_key is stable content: the check's own key,
  // or for entity-gate-failure rows the candidate text itself"). A check
  // capable of finding MULTIPLE candidates on one claim (e.g. several
  // entity-gate failures) must pass an explicit, distinguishing
  // candidateKey, or the second candidate's insert collides on
  // content_hash and is silently lost.
  const candidateKey = p.candidateKey === null || p.candidateKey === undefined || p.candidateKey === '' ? p.checkId : p.candidateKey;

  const contentHash = await evidenceContentHash({
    claimId: p.claimId,
    relation: p.relation,
    sourceUrl: p.sourceUrl,
    quote: p.quoteVerbatim,
    checkId: p.checkId,
    candidateKey: candidateKey,
  });

  return {
    claim_id: p.claimId,
    relation: p.relation,
    tier: p.tier,
    strength: p.strength === undefined ? null : p.strength,
    quote_verbatim: p.quoteVerbatim === undefined ? null : p.quoteVerbatim,
    source_url: p.sourceUrl === undefined ? null : p.sourceUrl,
    raw_signal_id: p.rawSignalId,
    content_hash: contentHash,
  };
}

// ============================================================================
// SS5.1(b) -- GitHub provenance vs. an independent anchor. MVP scope ruling
// (design.md SS5.1(b)): "MVP ships exactly one check: earliest commit author
// date versus the Show HN submission date, both of which are already in
// raw_signals -- zero new API calls."
//
// ⚠️ Measured against the LIVE database 2026-07-19: no raw_signals row of
// EITHER shape below is currently populated for the general corpus -- see
// task report. extractEarliestCommitAuthorDate() is written against the
// real, documented GitHub REST shape (`GET /repos/{owner}/{repo}/commits`)
// PLUS the one simplified shape already live in this project's own fixture
// data (db/fixtures/03-founder-score.sql's `first_commit_at`/
// `author_account_created_at` "provenance-spoofing bait" row -- an unrelated
// feature-03 red flag, not built by this file, but real proof the simplified
// shape is a real possibility a future ingestion task might also choose).
// Both shapes are supported so this check runs correctly the day either one
// is actually ingested, without a second migration of this file.
// ============================================================================

// A "commit object" per the real GitHub REST commits shape: `{ commit: {
// author: { date }, committer: { date } }, ... }`. Used only to disambiguate
// a bare commits array (ONE payload, shape (a)) from a LIST of several
// payloads passed together (see extractEarliestCommitAuthorDate below) --
// inspecting the first element is what makes that call ambiguity-free.
function looksLikeCommitObject(x) {
  return Boolean(x) && typeof x === 'object' && !Array.isArray(x) && x.commit && typeof x.commit === 'object';
}

// extractEarliestCommitAuthorDate(payloads) -> ISO date string, or null.
//
// `payloads`: a raw_signals.payload value, or an array of them, from
// github_api rows that may carry commit-author-date information, in EITHER
// of two shapes:
//   (a) the real GitHub REST commits response: an array of commit objects
//       `{ commit: { author: { date }, committer: { date } }, ... }`
//       (author date SURVIVES rebase; committer date does not -- SS5.1(b)).
//   (b) a single object carrying `first_commit_at` directly (the simplified
//       shape already live in this project's own fixture data, above).
// Multiple payloads may be supplied (e.g. paginated commit pages, or several
// repos); the EARLIEST author date found across ALL of them is returned,
// matching design's "earliest commit author date" phrasing exactly.
//
// A bare shape-(a) array IS itself one payload, and a caller passing several
// payloads together also does so as an array -- looksLikeCommitObject() on
// the first element is what tells "this array IS a commits list" apart from
// "this array is a LIST OF payloads, one of which might itself be a commits
// list": a commits list's elements satisfy looksLikeCommitObject(); a list
// of payloads' elements do not (they are themselves either commits arrays or
// plain shape-(b) objects, never a bare `{ commit: {...} }` at that level).
function extractEarliestCommitAuthorDate(payloads) {
  let earliestMs = null;
  let earliestIso = null;

  function consider(dateStr) {
    if (typeof dateStr !== 'string' || !dateStr) return;
    const ms = Date.parse(dateStr);
    if (!Number.isFinite(ms)) return;
    if (earliestMs === null || ms < earliestMs) {
      earliestMs = ms;
      earliestIso = dateStr;
    }
  }

  function process(payload) {
    if (!payload) return;
    if (Array.isArray(payload)) {
      if (payload.length > 0 && looksLikeCommitObject(payload[0])) {
        for (let j = 0; j < payload.length; j++) {
          const commitObj = payload[j];
          consider(commitObj && commitObj.commit && commitObj.commit.author && commitObj.commit.author.date);
        }
      } else {
        for (let j = 0; j < payload.length; j++) process(payload[j]);
      }
    } else if (typeof payload === 'object') {
      consider(payload.first_commit_at);
    }
  }

  process(payloads);
  return earliestIso;
}

// extractShowHnSubmittedAt(payload) -> ISO date string, or null.
//
// `payload`: ONE raw_signals.payload value from an hn_algolia row. The live
// corpus (measured 2026-07-19) carries at least four distinct hn_algolia
// shapes -- graceful degradation to null on all but the first is deliberate,
// not a defect:
//   - a real Algolia "story" hit tagged `show_hn` in `_tags`, carrying
//     `created_at` (ISO) and `created_at_i` (unix seconds) -- the shape this
//     function extracts from.
//   - a comment hit (`comment_text`/`parent_item`) -- not a submission at
//     all, returns null.
//   - a synthesized stub row (`{ note, hn_username }` or
//     `{ story_title, points }`) recorded when the identity was inferred
//     rather than queried live via the Algolia API -- carries no submission
//     timestamp, returns null.
function extractShowHnSubmittedAt(payload) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return null;
  const tags = Array.isArray(payload._tags) ? payload._tags : [];
  if (tags.indexOf('show_hn') === -1) return null;
  if (typeof payload.created_at === 'string' && payload.created_at) return payload.created_at;
  if (typeof payload.created_at_i === 'number' && Number.isFinite(payload.created_at_i)) {
    return new Date(payload.created_at_i * 1000).toISOString();
  }
  return null;
}

// "Months" (design.md SS5.1(b): "a repository whose earliest commit
// postdates the company's first public trace by MONTHS is the finding") is
// not pinned to an exact number anywhere in design.md. 60 days (~2 months)
// is this file's own choice: conservative enough that ordinary noise (a
// private repo made public a few weeks after its Show HN post, or a Show HN
// post describing a private beta that predates the public repo) does not
// trip it, while still catching a genuine multi-month gap. Configurable via
// the `thresholdDays` param -- not re-litigated as a hardcoded assumption.
const GH_PROVENANCE_GAP_THRESHOLD_DAYS = 60;

const MS_PER_DAY = 24 * 60 * 60 * 1000;

// checkGithubProvenance({ commitPayloads, hnPayloads, thresholdDays }) ->
//   {
//     checkId: 'gh_provenance',   -- matches design.md SS4.1's router
//                                    prefix_map `check` value verbatim
//     status: 'insufficient_data' | 'clean' | 'flagged',
//     earliestCommitAuthorDate, showHnSubmittedAt: ISO string | null,
//     gapDays: number | null,    -- earliest commit author date MINUS Show
//                                   HN date, in days; positive = commit
//                                   postdates the public trace (suspicious)
//     relation: 'supports' | 'contradicts' | null,
//     tier: 'documented' | null, -- Tier-1 per design.md SS6.0 ("commits,
//                                   direct codebase inspection")
//     summary: string | null,   -- quote_verbatim-ready sentence; contains
//                                   the FIXED phrase verbatim when flagged
//   }
//
// ⚠️ Output phrasing is FIXED (team lead instruction, restating design.md
// SS5.1(b)): "consistent with a rewritten or imported history" -- NEVER an
// accusation. Both git timestamps are fully user-controlled
// (`git commit --date`) and a squash performed before the first push is not
// observable at all -- the honest phrasing is part of the product, not a
// hedge. `status: 'clean'` produces relation:'supports' -- a repository
// whose earliest commit genuinely predates its own public trace is real,
// checkable confirmation of honest provenance, at the same Tier-1 strength
// as a flagged finding would have been.
function checkGithubProvenance(params) {
  const p = params || {};
  const thresholdDays = typeof p.thresholdDays === 'number' && p.thresholdDays >= 0 ? p.thresholdDays : GH_PROVENANCE_GAP_THRESHOLD_DAYS;

  const earliestCommitAuthorDate = extractEarliestCommitAuthorDate(p.commitPayloads);

  const hnList = Array.isArray(p.hnPayloads) ? p.hnPayloads : [p.hnPayloads];
  let showHnSubmittedAt = null;
  for (let i = 0; i < hnList.length; i++) {
    const candidate = extractShowHnSubmittedAt(hnList[i]);
    if (candidate && (showHnSubmittedAt === null || Date.parse(candidate) < Date.parse(showHnSubmittedAt))) {
      showHnSubmittedAt = candidate;
    }
  }

  if (!earliestCommitAuthorDate || !showHnSubmittedAt) {
    // "The check ran and found nothing definitive" -- SS9's
    // claim_verification_attempted event still needs to be written by the
    // caller (task B3 owns that), this function only reports the fact.
    return {
      checkId: 'gh_provenance',
      status: 'insufficient_data',
      earliestCommitAuthorDate: earliestCommitAuthorDate,
      showHnSubmittedAt: showHnSubmittedAt,
      gapDays: null,
      relation: null,
      tier: null,
      summary: null,
    };
  }

  const gapDays = Math.round((Date.parse(earliestCommitAuthorDate) - Date.parse(showHnSubmittedAt)) / MS_PER_DAY);
  const flagged = gapDays > thresholdDays;

  const summary = flagged
    ? 'Earliest commit author date (' + earliestCommitAuthorDate + ') is ' + gapDays +
      " day(s) after the company's earliest independent public trace (Show HN submission, " + showHnSubmittedAt +
      ') -- consistent with a rewritten or imported history.'
    : 'Earliest commit author date (' + earliestCommitAuthorDate +
      ") predates or closely precedes the company's earliest independent public trace (Show HN submission, " +
      showHnSubmittedAt + '); no rewritten-history signature detected.';

  return {
    checkId: 'gh_provenance',
    status: flagged ? 'flagged' : 'clean',
    earliestCommitAuthorDate: earliestCommitAuthorDate,
    showHnSubmittedAt: showHnSubmittedAt,
    gapDays: gapDays,
    relation: flagged ? 'contradicts' : 'supports',
    tier: 'documented',
    summary: summary,
  };
}

// ============================================================================
// SS5.1(c) -- denominator extraction. The Presto/SEC lesson: "95% without
// intervention" turned out to mean without intervention BY RESTAURANT
// STAFF -- the number was real, the definition/denominator was misleading.
// No denominator -> the claim cannot reach `verified`; it caps at
// `unverified` and generates a deep-dive question. Deterministic, zero-LLM,
// per design.md SS5.1's own "all zero-LLM" framing for this sub-check list.
//
// Scope, stated plainly (this is a text-pattern proxy, not semantic
// understanding, and both limits below are deliberate rather than
// oversights):
//   - Only `%`-sign rate/percentage claims are covered. "X per Y" / "X out
//     of Y" ratio phrasing without a % sign is not extracted (cut from MVP,
//     same "cut" framing as SS5.1(d)'s vanity-metric check).
//   - Exactly 0% and 100% are treated as BOUNDARY/absolute claims ("100%
//     offline", "100% private", "100% free" -- all real, common phrasings in
//     this project's own corpus, describing an architecture property, not a
//     sampled rate) and are excluded from denominator-checking entirely.
//     Only percentages strictly between 0 and 100 imply an underlying
//     measured sample that could have a hidden denominator -- consistent
//     with the Presto example itself (95%, strictly in range).
//   - "Has a denominator" is approximated as "a bare number (not itself
//     followed by %) appears within a character window around the
//     percentage" -- e.g. "40% of our 1,200 beta users" finds "1,200";
//     "94% fraud-catch accuracy -- well above the roughly 70% typical of..."
//     finds NEITHER number a denominator for the other, because both are
//     themselves %-attached. This heuristic can be fooled by an unrelated
//     nearby number (a year, a dollar figure) -- a deliberate, documented
//     simplicity-over-precision tradeoff for a zero-LLM check: an overly
//     permissive match only means THIS gate does not additionally cap the
//     claim -- every other REQ-004 guard (entity gate, tier requirements,
//     router class gating, SS7.4's verdict table) still applies, so the
//     blast radius of a false "denominator found" reading is bounded.
// ============================================================================

const DENOMINATOR_WINDOW_CHARS = 200;
const DENOMINATOR_BOUNDARY_VALUES = Object.freeze([0, 100]);

// A number NOT immediately followed by (optional whitespace +) '%'. The two
// negative lookarounds -- (?<!\d) before, (?![\d.]) after -- prevent matching
// a truncated PREFIX of a percentage's own digits (e.g. "9" out of "94%", or
// "0" out of "0.3%") via quantifier backtracking; without them a percentage
// figure would spuriously "find" a denominator inside itself.
const BARE_NUMBER_RE = /(?<!\d)(\d[\d,]*(?:\.\d+)?)(?![\d.])(?!\s?%)/;

function extractDenominator(text, options) {
  const opts = options || {};
  const windowChars = typeof opts.windowChars === 'number' ? opts.windowChars : DENOMINATOR_WINDOW_CHARS;
  const boundaryValues = Array.isArray(opts.boundaryValues) ? opts.boundaryValues : DENOMINATOR_BOUNDARY_VALUES;
  const source = typeof text === 'string' ? text : '';

  const matches = [];
  const percentRe = /(\d+(?:\.\d+)?)\s?%/g;
  let m;
  while ((m = percentRe.exec(source)) !== null) {
    const raw = m[0];
    const value = parseFloat(m[1]);
    if (boundaryValues.indexOf(value) !== -1) continue; // boundary/absolute claim, not a sampled rate

    const start = Math.max(0, m.index - windowChars);
    const end = Math.min(source.length, m.index + raw.length + windowChars);
    const window = source.slice(start, m.index) + source.slice(m.index + raw.length, end);

    const bareMatch = BARE_NUMBER_RE.exec(window);
    const hasDenominator = Boolean(bareMatch);

    matches.push({
      raw: raw,
      value: value,
      hasDenominator: hasDenominator,
      denominatorExcerpt: hasDenominator ? bareMatch[0] : null,
      deepDiveQuestion: hasDenominator
        ? null
        : 'What is the denominator behind "' + raw + '" -- ' + value + '% of what, measured against which sample size, population, or time window?',
    });
  }

  return {
    hasPercentageClaim: matches.length > 0,
    matches: matches,
    // A single denominator-less rate claim is enough to cap the WHOLE claim
    // (design.md: "the claim cannot reach verified") -- this is a per-CLAIM
    // (i.e. per claims.text_verbatim row) analysis, not per-number.
    cappedAtUnverified: matches.some(function (x) { return !x.hasDenominator; }),
    deepDiveQuestions: matches.filter(function (x) { return !x.hasDenominator; }).map(function (x) { return x.deepDiveQuestion; }),
  };
}

