// claim as supported when the source's point value falls inside
// [low, high] (each edge still getting the type's usual tolerance).
//
// Fixed post-port, 2026-07-19, per QA pass Finding 2(b) (a real behavioural
// divergence from the Python original, not a load-bearing design choice):
// the negation check originally fired whenever the source window simply
// failed to RESTATE the quote's negation -- which is the normal case, since
// an independently-collected source rarely repeats a claim's exact wording,
// let alone its negative phrasing. That fired on ordinary, true, pre-seed
// disclosures ("The company does not currently generate revenue") the
// instant the (correct, unrelated) source didn't happen to say the same
// thing. Tightened to require a POSITIVE assertion: the quote's negation
// predicate (e.g. "indemnify" in "shall not indemnify") must appear in some
// sentence of the aligned source window WITHOUT a negation cue of its own --
// i.e. the source itself asserts the opposite -- before it is flagged. See
// `negationPredicateWords` below.
//
// Zero imports -- this file is inlined verbatim into an n8n Code node by
// n8n/build-f05-workflow.py (n8n cannot `require()` from this repo, no
// bind-mount). Self-contained CommonJS, no `require()`, no `Date.now()`, no
// `Math.random()`, no top-level side effects. Pure functions only.

'use strict';

// ============================================================================
// Tunables
// ============================================================================

// Relative tolerance for numeric/currency/percent support (rounding !=
// fabrication).
const NUMERIC_TOLERANCE = 0.05;

// Cross-unit duration comparison (month=~30d, year=~365d) is approximate, so
// durations use a looser tolerance than exact currency/percent figures --
// "4 weeks" (28d) must not be flagged against "1 month" (30d).
const DURATION_TOLERANCE = 0.15;

// Currency like $1,200,000 / $1.2M / $904K / $3 billion / $50MM. The
// magnitude suffix requires a trailing word boundary so it never swallows
// the leading letter of a following word (e.g. the "m" of "monthly" must NOT
// inflate $50,000 to $50B).
const CURRENCY_RE = /\$\s*[\d,]+(?:\.\d+)?(?:\s*(?:m|b|k|mm|million|billion|thousand)\b)?/gi;

// Durations like "90 days", "12 months", "3 years", "6 weeks".
const DURATION_RE = /\b(\d+)\s+(day|days|month|months|year|years|week|weeks)\b/gi;

// Percentages like "15%" or "15 %".
const PERCENT_RE = /\b(\d+(?:\.\d+)?)\s*%/g;

// Numeric ranges -- "$1-2 million", "10-15%", "12-18 months" -- matched as a
// SINGLE token, low and high sharing one trailing unit/suffix. See the file
// header's Finding 2(a) divergence note: without these, the single-value
// regexes above mis-tokenize a range's low bound as bare and unit-less.
// Matched BEFORE (and its span excluded from) the single-value regexes.
const CURRENCY_RANGE_RE = /\$\s*([\d,]+(?:\.\d+)?)\s*[-–]\s*([\d,]+(?:\.\d+)?)(?:\s*(m|b|k|mm|million|billion|thousand)\b)?/gi;
const DURATION_RANGE_RE = /\b(\d+)\s*[-–]\s*(\d+)\s+(day|days|month|months|year|years|week|weeks)\b/gi;
const PERCENT_RANGE_RE = /\b(\d+(?:\.\d+)?)\s*[-–]\s*(\d+(?:\.\d+)?)\s*%/g;

// STRONG negation / liability-flip cues only. Deliberately EXCLUDES bare "no"
// (which fires on innocuous comparison phrases like "no later than", "no
// less than", "at no additional cost") and "without"/"except"/"none". Flags a
// negation mismatch ONLY when the quote asserts one of these strong
// negations that appears NOWHERE in the cited source -- a near-certain
// fabrication signal with effectively zero false positives.
const NEGATION_RE = new RegExp(
  '(?:\\b(?:shall|will|would|may|can|must|does|do|is|are|was|were|has|have)\\s+not\\b'
  + "|\\b(?:cannot|won't|can't|shan't|isn't|aren't|wasn't|weren't|doesn't|don't|didn't|hasn't|haven't|wouldn't|couldn't|shouldn't)\\b"
  + '|\\bno\\s+(?:obligation|liability|liabilities|right|rights|warrant(?:y|ies)|refund|indemnit)'
  + '|\\bnot\\s+(?:liable|entitled|obligated|responsible|permitted|required|bound)\\b'
  + '|\\bnever\\b)',
  'i',
);

// ============================================================================
// Normalization
// ============================================================================

// NFKC-normalize, collapse whitespace, fold curly apostrophes, lowercase.
// Curly apostrophes (U+2019 RIGHT SINGLE QUOTATION MARK, U+02BC MODIFIER
// LETTER APOSTROPHE) are folded to ASCII "'" so contraction-based negations
// ("won't", "isn't") match regardless of the document's typography.
function normalize(text) {
  const nfkc = String(text).normalize('NFKC');
  const foldedApostrophes = nfkc.replace(/’/g, "'").replace(/ʼ/g, "'");
  return foldedApostrophes.replace(/\s+/g, ' ').trim().toLowerCase();
}

// ============================================================================
// Currency parsing
// ============================================================================

// Parse a currency match (e.g. "$1.2M", "$50MM") to a float dollar value.
// Longest-alternative-first ('mm'/'million' checked before bare 'm', etc.) so
// a multi-letter suffix is stripped as one unit -- see the file header note
// on the Python original's single-character-strip bug this avoids.
function currencyToFloat(raw) {
  let s = raw.toLowerCase().replace(/\$/g, '').replace(/,/g, '').trim();
  let multiplier = 1.0;
  if (/(?:mm|million)$/.test(s)) {
    s = s.replace(/(?:mm|million)$/, '').trim();
    multiplier = 1_000_000.0;
  } else if (s.endsWith('m')) {
    s = s.slice(0, -1).trim();
    multiplier = 1_000_000.0;
  } else if (s.endsWith('billion')) {
    s = s.replace(/billion$/, '').trim();
    multiplier = 1_000_000_000.0;
  } else if (s.endsWith('b')) {
    s = s.slice(0, -1).trim();
    multiplier = 1_000_000_000.0;
  } else if (s.endsWith('thousand')) {
    s = s.replace(/thousand$/, '').trim();
    multiplier = 1_000.0;
  } else if (s.endsWith('k')) {
    s = s.slice(0, -1).trim();
    multiplier = 1_000.0;
  }
  if (!/^\d+(?:\.\d+)?$/.test(s)) return null;
  return parseFloat(s) * multiplier;
}

// Canonical key for a currency token: "$<number>" with no separators or
// magnitude suffix, so "$1.2M" and "$1200000" collapse to the same key.
// (Python's original branches on `value.is_integer()` to avoid a trailing
// ".0" -- unnecessary here, since JS's own number-to-string coercion already
// renders an integer-valued float without one.)
function canonicalCurrency(raw) {
  const value = currencyToFloat(raw);
  if (value === null) return raw.trim();
  return `$${value}`;
}

// ============================================================================
// Duration parsing
// ============================================================================

// Day-equivalent factor per unit stem. Shared by durationValue() (single
// tokens) and the range extraction in extractSalientTokens() below, so
// "12-18 months" and a bare "12 months" convert with identical arithmetic.
const DURATION_FACTORS = { day: 1.0, week: 7.0, month: 30.0, year: 365.0 };

// Normalize a duration unit to its plural canonical form (day -> days).
function singularUnit(unit) {
  const u = unit.toLowerCase().replace(/s$/, '');
  return `${u}s`;
}

// Convert a canonical duration token ("90 days") to a comparable day count.
function durationValue(token) {
  const m = /^(\d+)\s+(day|month|year|week)s?$/.exec(token);
  if (!m) return null;
  return parseFloat(m[1]) * DURATION_FACTORS[m[2]];
}

// ============================================================================
// Salient-token extraction
// ============================================================================

// True if `index` falls inside any [start, end) span. Used to keep the
// single-value regexes below from re-tokenizing a range's low/high number as
// an untethered bare value (file header, Finding 2(a)).
function withinSpan(index, spans) {
  return spans.some(([start, end]) => index >= start && index < end);
}

// Extract the material tokens (currency, duration, percent, negation) from
// `text`. Returns { currency: Set<string>, duration: Set<string>,
// percent: Set<string>, negation: boolean, currencyRanges: {low,high}[],
// durationRanges: {low,high}[] (bounds in days), percentRanges: {low,high}[]
// }. Ranges are extracted first so their spans can be excluded from the
// single-value Sets.
function extractSalientTokens(text) {
  const norm = normalize(text);

  const currencyRanges = [];
  const currencyRangeSpans = [];
  for (const match of norm.matchAll(CURRENCY_RANGE_RE)) {
    currencyRangeSpans.push([match.index, match.index + match[0].length]);
    const suffix = match[3] || '';
    const low = currencyToFloat(`$${match[1]}${suffix}`);
    const high = currencyToFloat(`$${match[2]}${suffix}`);
    if (low !== null && high !== null) currencyRanges.push({ low, high });
  }

  const durationRanges = [];
  const durationRangeSpans = [];
  for (const match of norm.matchAll(DURATION_RANGE_RE)) {
    durationRangeSpans.push([match.index, match.index + match[0].length]);
    const factor = DURATION_FACTORS[match[3].toLowerCase().replace(/s$/, '')];
    durationRanges.push({ low: parseFloat(match[1]) * factor, high: parseFloat(match[2]) * factor });
  }

  const percentRanges = [];
  const percentRangeSpans = [];
  for (const match of norm.matchAll(PERCENT_RANGE_RE)) {
    percentRangeSpans.push([match.index, match.index + match[0].length]);
    percentRanges.push({ low: parseFloat(match[1]), high: parseFloat(match[2]) });
  }

  const currency = new Set();
  for (const match of norm.matchAll(CURRENCY_RE)) {
    if (withinSpan(match.index, currencyRangeSpans)) continue;
    currency.add(canonicalCurrency(match[0]));
  }

  const duration = new Set();
  for (const match of norm.matchAll(DURATION_RE)) {
    if (withinSpan(match.index, durationRangeSpans)) continue;
    duration.add(`${match[1]} ${singularUnit(match[2])}`);
  }

  const percent = new Set();
  for (const match of norm.matchAll(PERCENT_RE)) {
    if (withinSpan(match.index, percentRangeSpans)) continue;
    percent.add(`${match[1]}%`);
  }

  const negation = NEGATION_RE.test(norm);

  return {
    currency, duration, percent, negation, currencyRanges, durationRanges, percentRanges,
  };
}

// ============================================================================
// Numeric support check
// ============================================================================

// True if `value` matches any candidate within `tolerance` (0 matches 0).
function numericSupported(value, candidates, tolerance = NUMERIC_TOLERANCE) {
  for (const c of candidates) {
    if (c === 0 && value === 0) return true;
    if (c !== 0 && Math.abs(value - c) / Math.abs(c) <= tolerance) return true;
  }
  return false;
}

// ============================================================================
// Range support (file header, Finding 2(a))
// ============================================================================

// True if `value` falls inside [low, high], each bound loosened by
// `tolerance` -- the same relative tolerance a bare value already gets, so a
// source figure at the very edge of a quoted range isn't penalized for
// ordinary rounding.
function valueInRange(value, low, high, tolerance) {
  const loLimit = low - Math.abs(low) * tolerance;
  const hiLimit = high + Math.abs(high) * tolerance;
  return value >= loLimit && value <= hiLimit;
}

// True if two (tolerance-loosened) ranges overlap.
function rangesOverlap(a, b, tolerance) {
  const aLo = a.low - Math.abs(a.low) * tolerance;
  const aHi = a.high + Math.abs(a.high) * tolerance;
  const bLo = b.low - Math.abs(b.low) * tolerance;
  const bHi = b.high + Math.abs(b.high) * tolerance;
  return aLo <= bHi && bLo <= aHi;
}

// A bare quoted value is supported if it matches a bare source value
// (existing tolerance rule) OR falls inside a source-stated range.
function scalarSupported(value, sourceScalars, sourceRanges, tolerance) {
  if (numericSupported(value, sourceScalars, tolerance)) return true;
  for (const r of sourceRanges) {
    if (valueInRange(value, r.low, r.high, tolerance)) return true;
  }
  return false;
}

// A quoted range ("$1-2 million") is supported if the source's point figure
// falls inside it, or a source-stated range overlaps it. Without this, only
// the range's high bound would survive as a bare token (see file header) and
// a true point figure inside the range would be flagged as unsupported.
function rangeSupported(range, sourceScalars, sourceRanges, tolerance) {
  for (const v of sourceScalars) {
    if (valueInRange(v, range.low, range.high, tolerance)) return true;
  }
  for (const r of sourceRanges) {
    if (rangesOverlap(range, r, tolerance)) return true;
  }
  return false;
}

// ============================================================================
// Negation window alignment
// ============================================================================

// Return the slice of `source` aligned to `quote`, for local negation checks.
//
// Anchors on the quote's longest run of content words and returns that
// region of the source +/- `margin` chars. When no anchor is found (the
// quote's content is not in the source at all), returns the whole
// (normalized) source so a genuinely unsupported negated quote is still
// evaluated. Pure string work -- no deps.
function alignedWindow(quote, source, margin = 240) {
  const nSource = normalize(source);
  const nQuote = normalize(quote);
  if (!nQuote || !nSource) return source;

  const words = nQuote.split(' ');
  const maxSpan = Math.min(words.length, 12);
  // Mirrors Python's `range(min(len(words), 12), 2, -1)`: tries progressively
  // shorter leading word-runs, stopping once span would drop to 2 or below.
  for (let span = maxSpan; span > 2; span -= 1) {
    const probe = words.slice(0, span).join(' ');
    const idx = nSource.indexOf(probe);
    if (idx !== -1) {
      const start = Math.max(0, idx - margin);
      const end = Math.min(nSource.length, idx + probe.length + margin);
      return nSource.slice(start, end);
    }
  }
  // No alignment anchor -> evaluate against the full source (conservative).
  return nSource;
}

// ============================================================================
// Negation predicate extraction (file header, Finding 2(b))
// ============================================================================

// Function words and the negation cue words themselves -- excluded when
// deriving a negation's "predicate" below, so the predicate is always
// genuine content (e.g. "indemnify", "liable", "obligation"), never a piece
// of the negation machinery around it.
const NEGATION_SKIP_WORDS = new Set([
  'shall', 'will', 'would', 'may', 'can', 'must', 'does', 'do', 'is', 'are', 'was', 'were', 'has', 'have',
  'not', 'no', 'never',
  'cannot', "won't", "can't", "shan't", "isn't", "aren't", "wasn't", "weren't",
  "doesn't", "don't", "didn't", "hasn't", "haven't", "wouldn't", "couldn't", "shouldn't",
  'the', 'a', 'an', 'to', 'of', 'for', 'in', 'on', 'at', 'and', 'or', 'this', 'that',
  'with', 'by', 'it', 'its', 'as', 'than', 'be', 'been', 'being',
]);

function escapeRegExp(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Split into rough sentence-like chunks on terminal punctuation. Coarse on
// purpose -- just enough so a positive assertion of the predicate elsewhere
// in a long, unrelated clause of the window isn't credited to the negation
// being checked.
function splitSentences(text) {
  return text.split(/[.!?;]+/).map((s) => s.trim()).filter(Boolean);
}

// From a NEGATION_RE match on the (normalized) quote, derive up to 4 content
// words the negation attaches to -- combining the match's own last word(s)
// (carries the predicate for the "no <noun>" / "not <adjective>" cues, e.g.
// "obligation" in "no obligation") with the words immediately following the
// match (carries the predicate for the modal/contraction/"never" cues, e.g.
// "indemnify" in "shall not indemnify"). Returns [] when nothing but
// function/cue words follow -- callers treat that as "cannot check", not
// "mismatch" (see the false-negative bias note on the call site).
function negationPredicateWords(normQuote, match) {
  const matchWords = match[0].split(/[^a-z0-9']+/i).filter(Boolean);
  const after = normQuote.slice(match.index + match[0].length)
    .split(/[^a-z0-9']+/i).filter(Boolean).slice(0, 8);
  const predicate = [];
  for (const w of [...matchWords, ...after]) {
    if (predicate.length >= 4) break;
    if (w.length < 3 || NEGATION_SKIP_WORDS.has(w)) continue;
    predicate.push(w);
  }
  return predicate;
}

// ============================================================================
// Main guard
// ============================================================================

// Return human-readable mismatches where `quote`'s salient tokens lack
// support in `source`.
//
// Returns an empty array when the source supports every salient token in the
// quote (within numeric tolerance), or when either input is empty (absence
// of source is handled upstream as non-blocking, not as a contradiction
// here).
function quoteSalienceMismatches(quote, source) {
  if (!String(quote).trim() || !String(source).trim()) return [];

  const q = extractSalientTokens(quote);
  const s = extractSalientTokens(source);
  const mismatches = [];

  // Currency: every quoted amount (bare or ranged) must be supported
  // (+/-tolerance) by the source, and vice versa for a quoted range -- see
  // the file header's Finding 2(a) note.
  const sourceAmounts = new Set();
  for (const raw of s.currency) {
    const v = currencyToFloat(raw);
    if (v !== null) sourceAmounts.add(v);
  }
  for (const raw of q.currency) {
    const val = currencyToFloat(raw);
    if (val !== null && !scalarSupported(val, sourceAmounts, s.currencyRanges, NUMERIC_TOLERANCE)) {
      mismatches.push(`currency ${raw} in quote not supported by source`);
    }
  }
  for (const range of q.currencyRanges) {
    if (!rangeSupported(range, sourceAmounts, s.currencyRanges, NUMERIC_TOLERANCE)) {
      mismatches.push(`currency range $${range.low}-$${range.high} in quote not supported by source`);
    }
  }

  // Durations: compared in normalized days, with a looser tolerance because
  // cross-unit conversion (month=~30d, year=~365d) is approximate.
  const sourceDays = new Set();
  for (const tok of s.duration) {
    const v = durationValue(tok);
    if (v !== null) sourceDays.add(v);
  }
  for (const tok of q.duration) {
    const val = durationValue(tok);
    if (val !== null && !scalarSupported(val, sourceDays, s.durationRanges, DURATION_TOLERANCE)) {
      mismatches.push(`duration '${tok}' in quote not supported by source`);
    }
  }
  for (const range of q.durationRanges) {
    if (!rangeSupported(range, sourceDays, s.durationRanges, DURATION_TOLERANCE)) {
      mismatches.push(`duration range ${range.low}-${range.high} days in quote not supported by source`);
    }
  }

  // Percentages: exact numeric support (+/-tolerance).
  const sourcePcts = new Set();
  for (const p of s.percent) sourcePcts.add(parseFloat(p.slice(0, -1)));
  for (const p of q.percent) {
    const val = parseFloat(p.slice(0, -1));
    if (!scalarSupported(val, sourcePcts, s.percentRanges, NUMERIC_TOLERANCE)) {
      mismatches.push(`percentage ${p} in quote not supported by source`);
    }
  }
  for (const range of q.percentRanges) {
    if (!rangeSupported(range, sourcePcts, s.percentRanges, NUMERIC_TOLERANCE)) {
      mismatches.push(`percentage range ${range.low}%-${range.high}% in quote not supported by source`);
    }
  }

  // Negation -- DIRECTIONAL, WINDOWED, and requires a POSITIVE ASSERTION, not
  // merely an absence of restatement (file header, Finding 2(b)): we derive
  // the negation's predicate from the quote (e.g. "indemnify" in "shall not
  // indemnify"), then flag only when some sentence of the region of the
  // source aligned to the quote contains that SAME predicate WITHOUT a
  // negation cue of its own -- i.e. the source itself positively asserts the
  // opposite. We never flag the reverse (source negates, quote doesn't) --
  // that is not a fabrication by the quote. If no predicate can be derived,
  // or no positive sentence is found, we do NOT flag: biased hard toward
  // false negatives on purpose, because missing a real fabrication costs one
  // finding, while a false accusation against a true founder claim breaks
  // REQ-004 -- the invariant this whole check exists to protect.
  if (q.negation) {
    const normQuote = normalize(quote);
    const negMatch = NEGATION_RE.exec(normQuote);
    const predicate = negMatch ? negationPredicateWords(normQuote, negMatch) : [];
    if (predicate.length > 0) {
      const sentences = splitSentences(alignedWindow(quote, source));
      const flipped = predicate.some((word) => {
        const wordRe = new RegExp(`\\b${escapeRegExp(word)}\\b`, 'i');
        return sentences.some((sentence) => wordRe.test(sentence) && !NEGATION_RE.test(sentence));
      });
      if (flipped) {
        mismatches.push('negation mismatch: source positively asserts the opposite of a negation in the quote');
      }
    }
  }

  return mismatches;
}

// ---- shared helpers (mirrors lib/f05/run.js's own, same names) ----
function buildEntityForRow(row, founderById, companyById) {
  const founder = row.card_founder_id ? founderById.get(row.card_founder_id) : null;
  const company = row.card_company_id ? companyById.get(row.card_company_id) : null;
  return {
    founderId: row.card_founder_id || null, companyId: row.card_company_id || null,
    founderName: founder ? founder.full_name : null, companyName: company ? company.name : null,
    companyDomain: company ? company.domain : null, companyAliases: company ? company.aliases : [],
  };
}

function extractSourceText(payload) {
  if (!payload || typeof payload !== 'object') return '';
  const keys = ['text', 'extracted_text', 'story_text', 'readme_excerpt', 'answer'];
  for (const key of keys) {
    if (typeof payload[key] === 'string' && payload[key]) return payload[key];
  }
  return '';
}

// design.md SS6: "Only CONTRADICTION candidates ever reach [the entity] gate" -- both
// checks below call applyEntityGate() ONLY on their own 'flagged'/mismatch branch, with
// NO matchWithLlm hook (step 3 is never invoked from this zero-LLM workflow -- owned by
// f05-contradiction-scan, matching lib/f05/run.js's own explicit choice). A candidate that
// fails steps 1-2 here is downgraded (step 4) and recorded as an auditable context row,
// never silently dropped and never escalated to an LLM from this workflow.
async function runGithubProvenanceCheck(row, bucket, founderById, companyById) {
  const result = checkGithubProvenance({ commitPayloads: bucket.commitPayloads, hnPayloads: bucket.hnPayloads });

  if (result.status === 'insufficient_data') {
    if (!bucket.githubSignal) {
      return { evidenceRow: null, contradiction: null, checkRan: bucket.commitPayloads.length > 0 || bucket.hnPayloads.length > 0 };
    }
    const evidenceRow = await buildEvidenceRow({
      claimId: row.claim_id, relation: 'context', tier: 'missing', quoteVerbatim: null, sourceUrl: null,
      rawSignalId: bucket.githubSignal, checkId: 'gh_provenance', candidateKey: 'insufficient_data',
    });
    return { evidenceRow, contradiction: null, checkRan: true };
  }

  if (result.status === 'clean') {
    const evidenceRow = await buildEvidenceRow({
      claimId: row.claim_id, relation: 'supports', tier: 'documented', quoteVerbatim: result.summary,
      sourceUrl: bucket.githubSourceUrl || null, rawSignalId: bucket.githubSignal,
      checkId: 'gh_provenance', candidateKey: result.earliestCommitAuthorDate,
    });
    return { evidenceRow, contradiction: null, checkRan: true };
  }

  // status === 'flagged' -- a CONTRADICTION CANDIDATE; must pass the entity gate.
  const entity = buildEntityForRow(row, founderById, companyById);
  const gate = await applyEntityGate({
    claimId: row.claim_id,
    candidate: { sourceUrl: bucket.githubSourceUrl || null, quote: result.summary, tier: 'documented' },
    rawSignal: { id: bucket.githubSignal, founderId: bucket.rsFounderId, companyId: bucket.rsCompanyId },
    entity,
  });

  if (gate.resolved) {
    const evidenceRow = await buildEvidenceRow({
      claimId: row.claim_id, relation: 'contradicts', tier: 'documented', quoteVerbatim: result.summary,
      sourceUrl: bucket.githubSourceUrl || null, rawSignalId: bucket.githubSignal,
      checkId: 'gh_provenance', candidateKey: result.earliestCommitAuthorDate,
    });
    return {
      evidenceRow,
      contradiction: {
        sourceUrl: bucket.githubSourceUrl || null, nature: 'temporal', severity: 'material',
        foundReality: result.summary,
        question: 'Can you walk us through the development history of this repository -- specifically why the earliest ' +
          'commit postdates your own earliest public trace by ' + result.gapDays + ' day(s)?',
        entityMatch: gate.entityMatch,
      },
      checkRan: true,
    };
  }

  const contextRow = await buildEvidenceRow({
    claimId: gate.contextRowFields.claimId, relation: gate.contextRowFields.relation, tier: gate.contextRowFields.tier,
    quoteVerbatim: gate.contextRowFields.quoteVerbatim, sourceUrl: gate.contextRowFields.sourceUrl,
    rawSignalId: gate.contextRowFields.rawSignalId, checkId: gate.contextRowFields.checkId,
    candidateKey: gate.contextRowFields.candidateKey,
  });
  return { evidenceRow: contextRow, contradiction: null, checkRan: true };
}

async function runQuoteGuardCheck(row, candidate, founderById, companyById) {
  const sourceText = extractSourceText(candidate.raw_signals && candidate.raw_signals.payload);
  const mismatches = quoteSalienceMismatches(row.text_verbatim, sourceText);
  if (!mismatches.length) return { evidenceRow: null, contradiction: null };

  const foundReality = mismatches.join('; ');
  const entity = buildEntityForRow(row, founderById, companyById);
  const rs = candidate.raw_signals || {};
  const gate = await applyEntityGate({
    claimId: row.claim_id,
    candidate: { sourceUrl: candidate.source_url || null, quote: foundReality, tier: 'documented' },
    rawSignal: { id: candidate.raw_signal_id, founderId: rs.founder_id, companyId: rs.company_id },
    entity,
  });

  if (gate.resolved) {
    const evidenceRow = await buildEvidenceRow({
      claimId: row.claim_id, relation: 'contradicts', tier: 'documented', quoteVerbatim: foundReality,
      sourceUrl: candidate.source_url || null, rawSignalId: candidate.raw_signal_id,
      checkId: 'quote_guard', candidateKey: foundReality,
    });
    return {
      evidenceRow,
      contradiction: {
        sourceUrl: candidate.source_url || null, nature: 'factual', severity: 'material', foundReality,
        question: 'Can you walk us through the figure(s) behind this claim -- our review of the cited source found: ' + foundReality,
        entityMatch: gate.entityMatch,
      },
    };
  }

  const contextRow = await buildEvidenceRow({
    claimId: gate.contextRowFields.claimId, relation: gate.contextRowFields.relation, tier: gate.contextRowFields.tier,
    quoteVerbatim: gate.contextRowFields.quoteVerbatim, sourceUrl: gate.contextRowFields.sourceUrl,
    rawSignalId: gate.contextRowFields.rawSignalId, checkId: gate.contextRowFields.checkId,
    candidateKey: gate.contextRowFields.candidateKey,
  });
  return { evidenceRow: contextRow, contradiction: null };
}

// ---- invocation: mirrors lib/f05/run.js main() steps 5-6 ----
const inp = $input.first().json;
const scopedRows = inp.scoped_rows || [];

const rawSignalsByEntity = new Map();
for (const rs of (inp.gh_raw_signals || [])) {
  const key = rs.founder_id || rs.company_id;
  if (!key) continue;
  if (!rawSignalsByEntity.has(key)) {
    rawSignalsByEntity.set(key, { commitPayloads: [], hnPayloads: [], githubSignal: null, githubSourceUrl: null, rsFounderId: null, rsCompanyId: null });
  }
  const bucket = rawSignalsByEntity.get(key);
  if (rs.source === 'github_api') {
    bucket.commitPayloads.push(rs.payload);
    if (!bucket.githubSignal) {
      bucket.githubSignal = rs.id; bucket.githubSourceUrl = rs.source_url;
      bucket.rsFounderId = rs.founder_id; bucket.rsCompanyId = rs.company_id;
    }
  } else if (rs.source === 'hn_algolia') {
    bucket.hnPayloads.push(rs.payload);
  }
}

const quoteCandidateByClaim = new Map((inp.quote_candidates || []).map(function (c) { return [c.claim_id, c]; }));
const founderById = new Map((inp.entity_founders || []).map(function (f) { return [f.id, f]; }));
const companyById = new Map((inp.entity_companies || []).map(function (c) { return [c.id, c]; }));

const evidenceRows = [];
const contradictionByClaim = {};
let ghProvenanceRan = 0, ghProvenanceInsufficientData = 0, quoteGuardRan = 0, quoteGuardMismatches = 0;
const denominatorFindingsByClaim = {};

for (const row of scopedRows) {
  const routing = row.routing;

  if (routing.check === 'gh_provenance') {
    const key = row.card_founder_id || row.card_company_id;
    const bucket = rawSignalsByEntity.get(key) || { commitPayloads: [], hnPayloads: [], githubSignal: null };
    const outcome = await runGithubProvenanceCheck(row, bucket, founderById, companyById);
    if (outcome.checkRan) {
      ghProvenanceRan += 1;
      if (outcome.evidenceRow && outcome.evidenceRow.tier === 'missing') ghProvenanceInsufficientData += 1;
    }
    if (outcome.evidenceRow) evidenceRows.push(outcome.evidenceRow);
    if (outcome.contradiction) contradictionByClaim[row.claim_id] = outcome.contradiction;
  }

  const quoteCandidate = quoteCandidateByClaim.get(row.claim_id);
  if (quoteCandidate) {
    quoteGuardRan += 1;
    const outcome = await runQuoteGuardCheck(row, quoteCandidate, founderById, companyById);
    if (outcome.evidenceRow) { quoteGuardMismatches += 1; evidenceRows.push(outcome.evidenceRow); }
    if (outcome.contradiction && !contradictionByClaim[row.claim_id]) contradictionByClaim[row.claim_id] = outcome.contradiction;
  }

  // design.md SS5.1(c) -- denominator extraction, advisory only (B2 ruling: no evidence
  // row -- it analyses the claim's own text and has no raw_signal_id to attach); folded
  // into this claim's attempted-event payload as deep_dive_questions below.
  const denom = extractDenominator(row.text_verbatim);
  if (denom.hasPercentageClaim && denom.cappedAtUnverified) {
    denominatorFindingsByClaim[row.claim_id] = denom.deepDiveQuestions;
  }
}

return [{ json: {
  ...inp, evidence_rows: evidenceRows, contradiction_by_claim: contradictionByClaim,
  denominator_findings_by_claim: denominatorFindingsByClaim,
  check_summary: {
    scoped_claims: scopedRows.length, gh_provenance_checks_run: ghProvenanceRan,
    gh_provenance_insufficient_data: ghProvenanceInsufficientData,
    quote_guard_checks_run: quoteGuardRan, quote_guard_mismatches: quoteGuardMismatches,
  },
} }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pg(method, path, body, prefer) {
  const headers = { apikey: KEY, Authorization: 'Bearer ' + KEY, 'Content-Type': 'application/json' };
  if (prefer) headers.Prefer = prefer;
  return await this.helpers.httpRequest({ method, url: SB + '/rest/v1/' + path, headers, body, json: true });
}
const inp = $input.first().json;
const rows = inp.evidence_rows || [];
// design.md SS10.1 -- evidence.content_hash is NOT NULL UNIQUE; the PostgREST upsert
// idiom (on_conflict= + Prefer: resolution=ignore-duplicates) is this workflow's
// equivalent of lib/f05/run.js's own `INSERT ... ON CONFLICT (content_hash) DO NOTHING`
// (run.js shells out to psql and can use raw SQL directly; this workflow only has
// PostgREST, whose documented upsert mechanism is exactly this header+query-param pair) --
// re-running this workflow against the same application inserts zero duplicate rows.
if (rows.length) {
  await pg.call(this, 'POST', 'evidence?on_conflict=content_hash', rows, 'resolution=ignore-duplicates,return=minimal');
}
return [{ json: { ...inp, evidence_written: rows.length } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
// design.md SS9's events need verdict_before/verdict_after -- 'after' can only be known
// once the evidence just written has landed, so claim_trust (the live view) is re-read
// here, matching lib/f05/run.js main() step 7's own re-read of the SAME rows post-write.
const cardIds = (inp.scope_cards || []).map(function (c) { return c.id; });
let rows = [];
if (cardIds.length) {
  rows = await pgGet.call(this, 'claim_trust?select=claim_id,derived_status&card_id=in.(' + cardIds.join(',') + ')');
}
const derived_status_after = {};
(rows || []).forEach(function (r) { derived_status_after[r.claim_id] = r.derived_status; });
return [{ json: { ...inp, derived_status_after } }];

// Hand-port of lib/f05/run.js's entityForClaim/buildAttemptedEventRow/
// buildUnmatchedTopicEventRow/buildVerifiedEventRow/buildContradictedEventRow -- run.js
// itself is a Node CLI, not a zero-import Code-node module, so this reproduces its LOGIC,
// not its literal source. design.md SS9: claim_verification_attempted is MANDATORY, one
// per scoped (routed) claim -- the ONLY trace distinguishing "we looked and found
// nothing" from "never routed". SS14: a documented/discovered-tier contradiction on a
// QUALITATIVE claim still gets its own claim_contradicted event even though the verdict
// itself stays pinned to 'unverified' by the view's class gate (SS7.1/SS7.4 row 1) --
// otherwise the finding reaches neither memo (06) nor dashboard (09).
function entityForClaim(row, applicationId) {
  if (row.card_founder_id) return { entityType: 'founder', entityId: row.card_founder_id };
  return { entityType: 'application', entityId: applicationId };
}

const inp = $input.first().json;
const scopedRows = inp.scoped_rows || [];
const afterByClaim = inp.derived_status_after || {};
const contradictionByClaim = inp.contradiction_by_claim || {};
const denominatorFindingsByClaim = inp.denominator_findings_by_claim || {};
const checkedAt = new Date().toISOString();
const ACTOR = 'f05-verify-claims';

const eventRows = [];
for (const row of scopedRows) {
  const routing = row.routing;
  const verdictBefore = row.derived_status;
  const verdictAfter = afterByClaim[row.claim_id] != null ? afterByClaim[row.claim_id] : verdictBefore;
  const contradiction = contradictionByClaim[row.claim_id];
  const ent = entityForClaim(row, inp.application_id);

  const attemptedPayload = {
    claim_id: row.claim_id, class: row.class, check: routing.check,
    verdict_before: verdictBefore, verdict_after: verdictAfter, checked_at: checkedAt, run_id: inp.run_id,
  };
  if (denominatorFindingsByClaim[row.claim_id]) attemptedPayload.deep_dive_questions = denominatorFindingsByClaim[row.claim_id];
  eventRows.push({ event_type: 'claim_verification_attempted', entity_type: ent.entityType, entity_id: ent.entityId, payload: attemptedPayload, actor: ACTOR });

  if (routing.unmatched_topic) {
    eventRows.push({
      event_type: 'router_unmatched_topic', entity_type: ent.entityType, entity_id: ent.entityId,
      payload: { claim_id: row.claim_id, topic: row.topic, run_id: inp.run_id, checked_at: checkedAt }, actor: ACTOR,
    });
  }

  if (verdictBefore !== verdictAfter && verdictAfter === 'verified') {
    eventRows.push({
      event_type: 'claim_verified', entity_type: ent.entityType, entity_id: ent.entityId,
      payload: {
        claim_id: row.claim_id, class: row.class, check: routing.check,
        verdict_before: verdictBefore, verdict_after: verdictAfter,
        source_url: contradiction ? contradiction.sourceUrl : null, checked_at: checkedAt, run_id: inp.run_id,
      }, actor: ACTOR,
    });
  }

  if (contradiction) {
    const base = {
      claim_id: row.claim_id, class: row.class, check: routing.check,
      verdict_before: verdictBefore, verdict_after: verdictAfter,
      source_url: contradiction.sourceUrl || null, checked_at: checkedAt, run_id: inp.run_id,
      nature: contradiction.nature, severity: contradiction.severity,
      found_reality: contradiction.foundReality, question: contradiction.question,
    };
    // design.md SS9 -- on the entity_type='application' fallback (no resolvable founder on
    // this claim's card), the payload OMITS founder_claim and entity_match.quote: the
    // 'carries no personal data' argument that makes an unpurgeable event acceptable must
    // be TRUE, not assumed. Built PER BRANCH, never inside the shared `base` object -- a
    // real bug B3 caught and fixed in lib/f05/run.js's own build (tracker.md): sharing the
    // object let the quote leak through the application-fallback path silently.
    const payload = ent.entityType === 'application'
      ? Object.assign({}, base, {
          entity_match: contradiction.entityMatch
            ? { resolved_by: contradiction.entityMatch.resolved_by, disambiguator: contradiction.entityMatch.disambiguator }
            : null,
        })
      : Object.assign({ founder_claim: row.text_verbatim }, base, { entity_match: contradiction.entityMatch });
    eventRows.push({ event_type: 'claim_contradicted', entity_type: ent.entityType, entity_id: ent.entityId, payload, actor: ACTOR });
  }
}

return [{ json: { ...inp, event_rows: eventRows } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pg(method, path, body, prefer) {
  const headers = { apikey: KEY, Authorization: 'Bearer ' + KEY, 'Content-Type': 'application/json' };
  if (prefer) headers.Prefer = prefer;
  return await this.helpers.httpRequest({ method, url: SB + '/rest/v1/' + path, headers, body, json: true });
}
const inp = $input.first().json;
// events is append-only (no uniqueness of its own, project-wide convention) -- no
// on_conflict here, a re-run legitimately appends a fresh batch.
const rows = inp.event_rows || [];
if (rows.length) {
  await pg.call(this, 'POST', 'events', rows, 'return=minimal');
}
return [{ json: { ...inp, events_written: rows.length } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pg(method, path, body, prefer) {
  const headers = { apikey: KEY, Authorization: 'Bearer ' + KEY, 'Content-Type': 'application/json' };
  if (prefer) headers.Prefer = prefer;
  return await this.helpers.httpRequest({ method, url: SB + '/rest/v1/' + path, headers, body, json: true });
}
const inp = $input.first().json;
// design.md SS6.0b -- confidence is a literal SQL NULL, never read from output_json. This
// workflow runs zero LLM calls (all SS5.1 checks are deterministic); this row is still the
// ledger proving a verification run happened at all, same 'ai_runs even when zero-LLM'
// pattern lib/f05/run.js's own step 10 uses (model: 'deterministic:f05_run' there).
await pg.call(this, 'POST', 'ai_runs', {
  task_type: 'verification', application_id: inp.application_id, founder_id: null, company_id: inp.company_id,
  model: 'deterministic:f05_verify_claims',
  output_json: Object.assign({ run_id: inp.run_id }, inp.check_summary || {}),
}, 'return=minimal');
return [{ json: inp }];

// Terminal node: its return value is both the webhook HTTP response (responseMode:
// lastNode) and the value returned to a caller invoking this as a sub-workflow (06/09/10).
const inp = $input.first().json;
return [{ json: {
  application_id: inp.application_id, run_id: inp.run_id, status: 'checked',
  scoped_claim_count: (inp.scoped_rows || []).length,
  evidence_written: inp.evidence_written || 0, events_written: inp.events_written || 0,
  check_summary: inp.check_summary,
} }];
